-- Products: Posters

  ('a0100000-0000-0000-0000-000000000002', 'Geometric Sunrise', 'geometric-sunrise', 'Warm geometric patterns that bring energy and light to any room.', 'Inspired by the golden hour, this geometric poster combines warm oranges, yellows, and soft pinks in a modern abstract composition. Printed on premium 300gsm paper with a subtle matte finish that reduces glare while maintaining vibrant colors. Makes a perfect statement piece or pairs beautifully with our other geometric designs. Frame not included.', 'c1000000-0000-0000-0000-000000000001', ARRAY['geometric', 'warm', 'abstract', 'modern'], 'PM-POST-002', 599, NULL, NULL, 30, 'in_stock', '/images/products/geometric-sunrise.jpg', false, true, false, true, '300gsm Art Paper', 'A3 (297×420mm)', 'Multi', 'Matte', '5-7 business days', true),

  ('a0100000-0000-0000-0000-000000000003', 'Urban Skyline Noir', 'urban-skyline-noir', 'Minimalist cityscape with bold black and white contrasts.', 'A sophisticated black and white poster featuring an abstract city skyline. The design uses bold geometric shapes and negative space to create depth and movement. Printed on 300gsm uncoated paper for a tactile, premium feel. Perfect for modern and minimalist interiors that need a statement without color. Frame not included.', 'c1000000-0000-0000-0000-000000000001', ARRAY['minimal', 'urban', 'black-white', 'cityscape'], 'PM-POST-003', 499, NULL, NULL, 20, 'in_stock', '/images/products/urban-skyline.jpg', false, false, true, true, '300gsm Art Paper', 'A3 (297×420mm)', 'Black/White', 'Matte', '5-7 business days', true),

  ('a0100000-0000-0000-0000-000000000004', 'Botanical Line Art Set', 'botanical-line-art-set', 'Elegant set of 3 botanical line art posters in olive and cream tones.', 'A curated set of three botanical line art prints that celebrate the beauty of nature through minimalist illustration. Each poster features a different plant species drawn in fine olive-green lines on a warm cream background. Printed on 250gsm premium paper. These prints work beautifully together or as individual pieces throughout your home. Frames not included.', 'c1000000-0000-0000-0000-000000000001', ARRAY['botanical', 'line-art', 'set', 'minimal', 'nature'], 'PM-POST-004', 1299, 999, 1299, 15, 'in_stock', '/images/products/botanical-set.jpg', true, true, false, true, '250gsm Premium Paper', '3× A4 (210×297mm)', 'Olive/Cream', 'Matte', '5-7 business days', true);

-- Products: 3D Textured Posters

  ('a0100000-0000-0000-0000-000000000006', 'Mountain Ridge Relief', 'mountain-ridge-relief', '3D topographic mountain art with real dimensional depth.', 'Experience the majesty of mountain ranges in three dimensions. This relief panel recreates the layered ridges of mountain terrain using advanced 3D printing. The multi-layer design creates genuine depth that changes appearance with different lighting angles. Available in natural white and charcoal finishes. Includes premium mounting kit for easy wall installation. A perfect gift for nature lovers and outdoor enthusiasts.', 'c1000000-0000-0000-0000-000000000002', ARRAY['3d-texture', 'mountain', 'topographic', 'nature', 'gift'], 'PM-3DT-002', 2999, NULL, NULL, 8, 'in_stock', '/images/products/mountain-relief.jpg', false, true, true, true, 'PLA Biodegradable', '14×18 inches', 'Natural White', 'Matte 3D Textured', '7-10 business days', true),

  ('a0100000-0000-0000-0000-000000000007', 'Hex Grid Texture Panel', 'hex-grid-texture-panel', 'Modern hexagonal 3D texture panel for contemporary spaces.', 'A contemporary take on geometric wall art, this hex grid panel features raised hexagonal patterns at varying heights, creating a honeycomb-like texture with depth. The precision 3D printing process ensures clean edges and consistent patterns. The panel comes in a premium black finish that adds sophistication to any modern interior. Includes mounting hardware.', 'c1000000-0000-0000-0000-000000000002', ARRAY['3d-texture', 'geometric', 'hexagon', 'modern', 'black'], 'PM-3DT-003', 1999, NULL, NULL, 12, 'in_stock', '/images/products/hex-grid.jpg', false, true, false, true, 'PLA Biodegradable', '12×12 inches', 'Charcoal Black', 'Matte 3D Textured', '7-10 business days', true);

-- Products: F1 Collection

  ('a0100000-0000-0000-0000-000000000009', 'F1 Circuit Layout - Spa', 'f1-circuit-spa', '3D printed Spa-Francorchamps circuit art - legendary corners in detail.', 'The legendary Spa-Francorchamps circuit rendered in stunning 3D relief. Features the iconic Eau Rouge, Raidillon, and the long Kemmel Straight in precision detail. Each sector is color-coded and the elevation changes of this famous circuit are represented in the depth of the print. Perfect alongside our Monaco piece for a circuit wall gallery. Mounting hardware included.', 'c1000000-0000-0000-0000-000000000003', ARRAY['f1', 'formula-1', 'spa', 'belgium', 'circuit', 'racing'], 'PM-F1-002', 3499, NULL, NULL, 6, 'in_stock', '/images/products/f1-spa.jpg', false, true, false, true, 'PLA Premium', '20×14 inches', 'Green/White', 'Satin 3D Printed', '7-10 business days', true),

  ('a0100000-0000-0000-0000-000000000010', 'F1 Car Silhouette Stand', 'f1-car-silhouette-stand', 'Sleek F1 car silhouette desk piece - a miniature icon for your desk.', 'A beautifully crafted F1 car silhouette desk piece that captures the aerodynamic essence of modern Formula 1 cars. 3D printed with fine detail, the silhouette features wheel profile, wing detail, and halo outline. The integrated stand allows display on any flat surface. Available in multiple team-inspired color options. Makes an excellent gift for any F1 fan.', 'c1000000-0000-0000-0000-000000000003', ARRAY['f1', 'formula-1', 'car', 'desk', 'gift', 'silhouette'], 'PM-F1-003', 899, 699, 899, 20, 'in_stock', '/images/products/f1-car-stand.jpg', false, false, true, true, 'PLA Premium', '8×3 inches', 'Black', 'Satin 3D Printed', '5-7 business days', true);

-- Products: Desk Accessories

  ('a0100000-0000-0000-0000-000000000012', 'Minimal Cable Organizer', 'minimal-cable-organizer', 'Clean, minimal cable management solution for a tidy workspace.', 'Say goodbye to tangled cables with this elegantly designed cable organizer. Features multiple channels for different cable sizes, a weighted base for stability, and a clean minimal aesthetic that blends with any desk setup. The soft-grip interior channels protect your cables while keeping them neatly routed. 3D printed with precision for a flawless finish.', 'c1000000-0000-0000-0000-000000000004', ARRAY['desk', 'cable', 'organizer', 'minimal', 'office'], 'PM-DESK-002', 499, NULL, NULL, 40, 'in_stock', '/images/products/cable-organizer.jpg', false, true, false, true, 'PLA Biodegradable', '6×2×2 inches', 'Charcoal', 'Matte', '5-7 business days', true),

  ('a0100000-0000-0000-0000-000000000013', 'Succulent Planter Trio', 'succulent-planter-trio', 'Set of 3 geometric mini planters for succulents and air plants.', 'A set of three beautifully designed geometric mini planters, each with a unique geometric shape inspired by natural crystal formations. Perfect for small succulents, air plants, or as decorative pieces on their own. Each planter has a drainage hole and comes with a matching saucer. The set includes one each of hexagonal, triangular, and cylindrical designs. 3D printed from PLA with a warm natural finish.', 'c1000000-0000-0000-0000-000000000004', ARRAY['desk', 'planter', 'succulent', 'geometric', 'set', 'gift'], 'PM-DESK-003', 999, 849, 999, 18, 'in_stock', '/images/products/planter-trio.jpg', false, false, false, true, 'PLA Biodegradable', '3×3×3 inches each', 'Sand Beige', 'Matte', '5-7 business days', true),

  ('a0100000-0000-0000-0000-000000000014', 'Laptop Stand - Arc', 'laptop-stand-arc', 'Premium ergonomic laptop stand with a clean arc design.', 'Elevate your work setup with this premium 3D printed laptop stand. The elegant arc design provides optimal viewing angle while allowing airflow underneath your laptop for better cooling. Supports laptops up to 16 inches and holds up to 5kg. The non-slip base and top surface ensure your laptop stays secure. Available in multiple color options. Some assembly required.', 'c1000000-0000-0000-0000-000000000004', ARRAY['desk', 'laptop', 'stand', 'ergonomic', 'premium'], 'PM-DESK-004', 1499, NULL, NULL, 12, 'in_stock', '/images/products/laptop-stand.jpg', true, false, false, true, 'PLA Biodegradable', '10×8×4 inches', 'Warm White', 'Matte', '7-10 business days', true);

