INSERT INTO categories (id, name, slug, description, image_url, sort_order, is_active) VALUES
  ('c1000000-0000-0000-0000-000000000001', 'Posters', 'posters', 'Premium quality art posters that transform your walls into gallery-worthy spaces.', '/images/categories/posters.jpg', 1, true),
  ('c1000000-0000-0000-0000-000000000002', '3D Textured Posters', '3d-textured-posters', 'Stunning 3D textured wall art with depth and dimension you can feel.', '/images/categories/3d-textured.jpg', 2, true),
  ('c1000000-0000-0000-0000-000000000003', 'F1 Collection', 'f1-collection', 'Formula 1 inspired 3D printed art and collectibles for motorsport enthusiasts.', '/images/categories/f1-collection.jpg', 3, true),
  ('c1000000-0000-0000-0000-000000000004', 'Desk Accessories', 'desk-accessories', 'Thoughtfully designed 3D printed accessories that elevate your workspace.', '/images/categories/desk-accessories.jpg', 4, true);
INSERT INTO products (id, title, slug, short_description, long_description, category_id, tags, sku, base_price, sale_price, compare_at_price, stock_quantity, stock_status, featured_image, is_featured, is_new_arrival, is_best_seller, is_published, material, size, color, finish, delivery_estimate, return_eligible) VALUES
  ('a0100000-0000-0000-0000-000000000001', 'Midnight Bloom Abstract', 'midnight-bloom-abstract', 'A captivating abstract poster featuring dark florals against a moody backdrop.', 'This premium art poster brings the mystery of midnight gardens into your space. Printed on 300gsm museum-quality art paper with archival inks, this piece features a rich palette of deep purples, blacks, and subtle gold accents. Each poster undergoes strict quality checks to ensure color accuracy and print clarity. Perfect for bedrooms, living rooms, or creative studios. Frame not included.', 'c1000000-0000-0000-0000-000000000001', ARRAY['abstract', 'floral', 'dark', 'premium'], 'PM-POST-001', 599, 449, 599, 25, 'in_stock', '/images/products/midnight-bloom.jpg', true, false, true, true, '300gsm Art Paper', 'A3 (297×420mm)', 'Multi', 'Matte', '5-7 business days', true),
INSERT INTO products (id, title, slug, short_description, long_description, category_id, tags, sku, base_price, sale_price, compare_at_price, stock_quantity, stock_status, featured_image, is_featured, is_new_arrival, is_best_seller, is_published, material, size, color, finish, delivery_estimate, return_eligible) VALUES
  ('a0100000-0000-0000-0000-000000000005', 'Wave Form Texture Panel', 'wave-form-texture-panel', 'Mesmerizing 3D printed wave pattern that creates stunning shadow play.', 'Our signature Wave Form panel brings walls to life with its undulating 3D texture. Created using precision 3D printing technology, the panel features organic wave patterns that catch light differently throughout the day, creating beautiful shadow play. Made from biodegradable PLA material in a warm white finish. Ready to hang with included mounting hardware. Each piece is unique due to the artisan printing process.', 'c1000000-0000-0000-0000-000000000002', ARRAY['3d-texture', 'wave', 'wall-art', 'premium', 'handmade'], 'PM-3DT-001', 2499, 1999, 2499, 10, 'in_stock', '/images/products/wave-texture.jpg', true, false, true, true, 'PLA Biodegradable', '12×16 inches', 'Warm White', 'Matte 3D Textured', '7-10 business days', true),
INSERT INTO products (id, title, slug, short_description, long_description, category_id, tags, sku, base_price, sale_price, compare_at_price, stock_quantity, stock_status, featured_image, is_featured, is_new_arrival, is_best_seller, is_published, material, size, color, finish, delivery_estimate, return_eligible) VALUES
  ('a0100000-0000-0000-0000-000000000008', 'F1 Circuit Layout - Monaco', 'f1-circuit-monaco', '3D printed Monaco GP circuit layout wall art - a must for F1 fans.', 'Celebrate the most glamorous race on the F1 calendar with this precision 3D printed circuit layout of the Circuit de Monaco. Every corner and chicane is faithfully reproduced in raised relief, with sector colors and DRS zones subtly marked. The piece includes a small info panel with circuit statistics. Made from premium PLA in team-inspired color combinations. A perfect centerpiece for any motorsport enthusiasts room. Mounting hardware included.', 'c1000000-0000-0000-0000-000000000003', ARRAY['f1', 'formula-1', 'monaco', 'circuit', 'racing', 'motorsport'], 'PM-F1-001', 3499, 2899, 3499, 8, 'in_stock', '/images/products/f1-monaco.jpg', true, false, true, true, 'PLA Premium', '18×14 inches', 'Red/White', 'Satin 3D Printed', '7-10 business days', true),
INSERT INTO products (id, title, slug, short_description, long_description, category_id, tags, sku, base_price, sale_price, compare_at_price, stock_quantity, stock_status, featured_image, is_featured, is_new_arrival, is_best_seller, is_published, material, size, color, finish, delivery_estimate, return_eligible) VALUES
  ('a0100000-0000-0000-0000-000000000011', 'Geodesic Pen Holder', 'geodesic-pen-holder', 'Striking geodesic design pen holder that turns organization into art.', 'Transform your desk with this architecturally inspired geodesic pen holder. The intricate triangulated surface creates a stunning visual pattern while providing sturdy support for pens, pencils, markers, and brushes. 3D printed from biodegradable PLA with a smooth matte finish. Available in multiple colors to match your workspace aesthetic. Fits 15-20 standard pens comfortably.', 'c1000000-0000-0000-0000-000000000004', ARRAY['desk', 'pen-holder', 'geometric', 'organizer', 'office'], 'PM-DESK-001', 699, 549, 699, 30, 'in_stock', '/images/products/geodesic-pen.jpg', true, true, true, true, 'PLA Biodegradable', '4×4×4 inches', 'Terracotta Orange', 'Matte', '5-7 business days', true),
