INSERT INTO reviews (product_id, reviewer_name, rating, title, body, status) VALUES
  ('a0100000-0000-0000-0000-000000000001', 'Ananya S.', 5, 'Absolutely stunning', 'The print quality is exceptional. Colors are even more vibrant in person. My living room looks so much better now!', 'approved'),
  ('a0100000-0000-0000-0000-000000000001', 'Rahul M.', 4, 'Great quality poster', 'Nice thick paper and crisp printing. Only wish it came with a frame option. Still, very happy with my purchase.', 'approved'),
  ('a0100000-0000-0000-0000-000000000005', 'Priya K.', 5, 'Unique and beautiful', 'Nothing like this available anywhere else! The 3D texture is mesmerizing and the shadow play throughout the day is beautiful. Worth every rupee.', 'approved'),
  ('a0100000-0000-0000-0000-000000000005', 'Vikram J.', 5, 'Perfect gift', 'Bought this as a housewarming gift and it was a huge hit. The packaging was excellent too. Will definitely order more.', 'approved'),
  ('a0100000-0000-0000-0000-000000000008', 'Arjun D.', 5, 'F1 fans must have this!', 'As an F1 fan, this is exactly what I wanted for my room. The circuit detail is incredible and the team colors are spot on. Ordered Spa next!', 'approved'),
  ('a0100000-0000-0000-0000-000000000011', 'Sneha R.', 4, 'Love the design', 'The geometric design is eye-catching and holds all my pens and brushes. The orange color is perfect. Slightly smaller than expected but still great.', 'approved'),
  ('a0100000-0000-0000-0000-000000000011', 'Dev P.', 5, 'Desk upgrade complete', 'This pen holder gets compliments every time someone sees my desk. Print quality is flawless. Already ordered the cable organizer.', 'approved'),
  ('a0100000-0000-0000-0000-000000000014', 'Kavita N.', 5, 'Solid and stylish', 'Looks premium, feels solid, works exactly as expected. My MacBook Pro 14 sits perfectly on it. Great airflow too.', 'approved');
