  ('value_props', 'Why PrintMacha?', NULL, '{"props": [{"icon": "printer", "title": "Precision Crafted", "description": "Every piece is 3D printed with meticulous attention to detail"}, {"icon": "leaf", "title": "Eco-Friendly Materials", "description": "Made with biodegradable PLA and sustainable practices"}, {"icon": "package", "title": "Secure Packaging", "description": "Each product is carefully packed for safe delivery across India"}, {"icon": "heart", "title": "Made with Love", "description": "Small batch production ensures quality over quantity"}]}', 6, true),
